import org.apache.spark.sql.{SparkSession, DataFrame}
import spray.json._
import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.server.Directives._
import akka.stream.ActorMaterializer

object SparkSQLQueryProcessor extends App {

  // Initialize Spark session
  val spark = SparkSession.builder()
    .appName("Spark SQL Query Processor")
    .config("spark.master", "local[*]")
    .getOrCreate()

  import spark.implicits._

  // Define a simple case class for the API request
  case class QueryRequest(query: String)

  // JSON format for deserialization
  implicit val queryFormat = jsonFormat1(QueryRequest)

  // Actor system and materializer for Akka HTTP
  implicit val system = ActorSystem("SparkSQLQueryProcessor")
  implicit val materializer = ActorMaterializer()
  import system.dispatcher

  // Route for handling POST requests
  val route =
    path("execute-query") {
      post {
        entity(as[String]) { queryJson =>
          try {
            // Deserialize JSON to case class
            val QueryRequest(query) = queryJson.parseJson.convertTo[QueryRequest]

            // Execute the query using Spark SQL
            val result: DataFrame = spark.sql(query)

            // Convert result DataFrame to JSON format for response
            complete(result.toJSON.collect().mkString("[", ",", "]"))
          } catch {
            case e: Exception => complete(s"Error executing query: ${e.getMessage}")
          }
        }
      }
    }

